import requests

def check_rate_limit_headers(url, custom_headers=None):
    known_rate_limit_headers = [
        "X-RateLimit-Limit",
        "X-RateLimit-Remaining",
        "X-RateLimit-Reset",
        "Retry-After",
        "RateLimit-Limit",
        "RateLimit-Remaining",
        "RateLimit-Reset",
        "RateLimit-Policy",
        "RateLimit-Period",
        "RateLimit-Reset-Time",
    ]

    try:
        response = requests.get(url, headers=custom_headers, timeout=10)
        response.raise_for_status()

        found_headers = {}
        for header_name in known_rate_limit_headers:
            if header_name in response.headers:
                found_headers[header_name] = response.headers[header_name]

        if found_headers:
            print(f"URL: {url}")
            for name, value in found_headers.items():
                print(f"{name}: {value}")
        else:
            print(f"URL: {url}")
            print("API oran sınırlama başlıkları bulunamadı.")

    except requests.exceptions.HTTPError as e:
        print(f"URL: {url}")
        print(f"HTTP Hatası: {e}")
        if e.response and "Retry-After" in e.response.headers:
            print(f"Retry-After: {e.response.headers['Retry-After']}")
    except requests.exceptions.ConnectionError as e:
        print(f"URL: {url}")
        print(f"Bağlantı Hatası: {e}")
    except requests.exceptions.Timeout as e:
        print(f"URL: {url}")
        print(f"Zaman Aşımı Hatası: {e}")
    except requests.exceptions.RequestException as e:
        print(f"URL: {url}")
        print(f"Bir Hata Oluştu: {e}")

if __name__ == "__main__":
    target_url = input("Kontrol edilecek URL'yi girin: ").strip()
    if not target_url:
        target_url = "https://api.github.com/users/octocat"
        print(f"URL girilmedi, varsayılan olarak '{target_url}' kullanılıyor.")

    common_headers = {
        "User-Agent": "RateLimitHeaderChecker/1.0"
    }

    check_rate_limit_headers(target_url, custom_headers=common_headers)
